<?php
namespace App\Http\Controllers\Api;
use App\Http\Controllers\Controller; use App\Http\Requests\PublicBookingStoreRequest; use App\Models\Appointment; use App\Models\Customer; use App\Models\Service; use App\Services\SquarePaymentService;
class PublicBookingController extends Controller { public function store(PublicBookingStoreRequest $r, SquarePaymentService $square){$v=$r->validated();$customer=Customer::firstOrCreate(['business_id'=>$v['business_id'],'email'=>$v['customer_email']],['name'=>$v['customer_name'],'phone'=>$v['customer_phone']??null]);$service=Service::findOrFail($v['service_id']);$start=now()->parse($v['starts_at']);$appt=Appointment::create(['business_id'=>$v['business_id'],'service_id'=>$service->id,'customer_id'=>$customer->id,'staff_user_id'=>$v['staff_user_id']??null,'starts_at'=>$start,'ends_at'=>$start->copy()->addMinutes($service->duration_minutes)]);$link=$square->createPaymentLink($appt);$appt->update(['square_payment_link_id'=>$link['id']]);return response()->json(['appointment_id'=>$appt->id,'payment_url'=>$link['url']],201);} }
